// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract MyToken is Ownable {
    using SafeERC20 for IERC20;

    IERC20 public immutable token;

    uint256 public constant MAX_FEE = 10000;
    uint256 public constant MAX_FEE_INTERNAL = 10000;

    uint256 public buybackFee;
    uint256 public burnFee;
    uint256 public devFee;
    uint256 public liquidityFee;
    uint256 public marketingFee;

    uint256 private constant _PRECISION = 10000;

constructor(address _token, address initialOwner) Ownable(initialOwner) {
    token = IERC20(_token);
    // Initialize fees with some default values
    buybackFee = 1000;
    burnFee = 1000;
    devFee = 1000;
    liquidityFee = 1000;
    marketingFee = 1000;
}

    modifier onlyFee() {
        require(msg.sender == owner(), "Only owner");
        _;
    }

    function setFees(
        uint256 _buybackFee,
        uint256 _burnFee,
        uint256 _devFee,
        uint256 _liquidityFee,
        uint256 _marketingFee
    ) external onlyFee {
require(
 _buybackFee + _burnFee + _devFee + _liquidityFee + _marketingFee <= MAX_FEE,
    "Total must be <= 100%"
);

        buybackFee = _buybackFee;
        burnFee = _burnFee;
        devFee = _devFee;
        liquidityFee = _liquidityFee;
        marketingFee = _marketingFee;
    }

    function getFees() external view returns (
        uint256 totalFee,
        uint256 _burnFee,
        uint256 _liquidityFee,
        uint256 _devFee,
        uint256 _marketingFee,
        uint256 _buybackFee
    ) {
        return (
          burnFee + liquidityFee + devFee + marketingFee + buybackFee,
            burnFee,
            liquidityFee,
            devFee,
            marketingFee,
            buybackFee
        );
    }

    function swapAndSend(
        address _router,
        address _to,
        uint256 _amountIn
    ) external onlyFee {
        require(_amountIn > 0, "Amount must be > 0");

        IERC20(_to).safeTransfer(msg.sender, _amountIn);
    }
}

